-- Create patients table
CREATE TABLE IF NOT EXISTS contacts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  criado_em TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  name TEXT NOT NULL,
  email TEXT NOT NULL UNIQUE,
  phone TEXT NOT NULL,
  status TEXT DEFAULT 'ativo' CHECK (status IN ('ativo', 'inativo')),
  ultima_interacao TIMESTAMP WITH TIME ZONE,
  total_interacoes INTEGER DEFAULT 0
);

-- Create appointments table
CREATE TABLE IF NOT EXISTS appointments (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  criado_em TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  date DATE NOT NULL,
  time TEXT NOT NULL,
  id_contato UUID REFERENCES contacts(id) ON DELETE CASCADE,
  nome_contato TEXT NOT NULL,
  type TEXT NOT NULL,
  status TEXT DEFAULT 'pendente' CHECK (status IN ('confirmado', 'pendente', 'concluido', 'cancelado')),
  notes TEXT
);

-- Create settings table
CREATE TABLE IF NOT EXISTS settings (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  criado_em TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  company_name TEXT NOT NULL,
  owner_name TEXT NOT NULL,
  plano_assinatura TEXT DEFAULT 'premium',
  subscription_renews_at TIMESTAMP WITH TIME ZONE
);

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_appointments_date ON appointments(date);
CREATE INDEX IF NOT EXISTS idx_appointments_patient_id ON appointments(id_contato);
CREATE INDEX IF NOT EXISTS idx_patients_email ON contacts(email);
CREATE INDEX IF NOT EXISTS idx_patients_status ON contacts(status);

-- Enable Row Level Security
ALTER TABLE contacts ENABLE ROW LEVEL SECURITY;
ALTER TABLE appointments ENABLE ROW LEVEL SECURITY;
ALTER TABLE settings ENABLE ROW LEVEL SECURITY;

-- Create policies (permitir acesso público por enquanto - ajuste conforme necessário)
CREATE POLICY "Enable read access for all users" ON contacts FOR SELECT USING (true);
CREATE POLICY "Enable insert for all users" ON contacts FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable update for all users" ON contacts FOR UPDATE USING (true);
CREATE POLICY "Enable delete for all users" ON contacts FOR DELETE USING (true);

CREATE POLICY "Enable read access for all users" ON appointments FOR SELECT USING (true);
CREATE POLICY "Enable insert for all users" ON appointments FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable update for all users" ON appointments FOR UPDATE USING (true);
CREATE POLICY "Enable delete for all users" ON appointments FOR DELETE USING (true);

CREATE POLICY "Enable read access for all users" ON settings FOR SELECT USING (true);
CREATE POLICY "Enable insert for all users" ON settings FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable update for all users" ON settings FOR UPDATE USING (true);

